char* fileBaseName (char* path) {
 int LastPos; char *name, *extension;
 extension = strchr(path,'.'); if (extension!=NULL) *extension = '\0';
 LastPos=strlen(path)-1;
 #ifndef WINDOWS
  if (path[LastPos] == '/') path[LastPos]='\0'; //remove possible trailing slash if foldername
  return basename(path);
 #else
  if (path[LastPos] == '\\') path[LastPos]='\0'; //remove possible trailing slash if foldername
  name=strrchr(path,'\\'); if(name==NULL) name=strrchr(path,'/');  return (name!=NULL)? name+1:path;
 #endif
}

void sanitizeName (char* string) {
 int i;
 for (i=0; string[i] != '\0'; ++i) {
  if ( !( string[i]=='_' || ('a'<=string[i] && string[i]<='z') || ('A'<=string[i] && string[i]<='Z')
       || ('0'<=string[i] && string[i]<='9') ) ) string[i] = '_';
 }
}

void generateResampleWindow (char* filename, int parts, int reso, int magnitude) {
 int i; double pi,phs,phsInc; //phs:phases in sinc, phsInc:increase-value of phase in each iteration
 static char ArrayName [1000];
 //int SincParts=SINCPARTS, SincPartsHalf=SINCPARTSHALF, SincPartReso = SINCPARTRESO, Magnitude = SINC_MAGNITUDE;
 if (parts) SincParts=parts; if (reso) SincPartReso=reso; if (magnitude) Magnitude=magnitude;//sscanf( parts, "%d", &SincParts ); sscanf( reso, "%d", &SincPartReso ); sscanf( magnitude, "%d", &Magnitude );
 SincPartsHalf = SincParts/2.0; windowSize = SincParts * SincPartReso; SincPartBits = BYTE_LOG2(SincPartReso);
 printf("Sinc-window generated: PartCount:%d,PartLengths:%d -> Size:%d, Magnitude:%d\n", SincParts, SincPartReso, windowSize, Magnitude );

 FILE *file = fopen( filename, "w" ); strcpy( ArrayName, fileBaseName(filename) ); sanitizeName( ArrayName );
 fprintf (file, "//Pre-calculated FIR nyquist-filter Sinc Hanning window for clean oversampling (replacing the suboptimal simple 'box'-filter averager oversampling)\n"
                "//(Generated by resources/tools/resampling code.)\n\n\nstatic const signed short %s [] = {"
                "  //PartCount:%d,PartLengths:%d -> Size:%d, Magnitude:%d\n \n ", ArrayName, SincParts, SincPartReso, windowSize, Magnitude );
 for (i = 0; i < OUTBUFLEN; i++) { buf[i] = 0.0f; }
 pi = atan(1.0) * 4.0;  phs = -(pi*SincPartsHalf);  phsInc = ((double)SincParts) * pi/windowSize; //atan(1.0) is 45 degrees, tan(45degrees) = 1.0
 for (i = 0; i < windowSize + 1; i++) { //sinc: sin(2 * pi * cutoff * i) / i*pi //Hanning: 0.5-0.5cos(2*pi*i/windowsize)
  if (i == (windowSize / 2)) windowTable[i] = 1.0f; //peak at the middle to 1.0 (not 0.999')
  else windowTable[i] = (float) ( /*Hann*/(cos(phs/SincPartsHalf) * 0.5 + 0.5) * /*sinc*/(sin(phs)/phs) ); //convolute (multiply element-pairs) of sinc by Hann-window
  SincWindow[i] = (signed short) round(windowTable[i]*Magnitude);
   fprintf( file, "%d,%s", SincWindow[i], !((i+(i<=windowSize/2))%SincParts) || i==windowSize/2 ? "\n " : "" );
  phs += phsInc; //  /*if(DEBUG)*/ fputc((char)(windowTable[i]*127+128),fp); // sinc
 }
 fprintf( file, "\n};\n\n\n"); fclose (file);
}



void processSample(signed int inputSignal, int *outBuf, int outBufLength, int bufPos) { //outBufLength=16, bufpos=0.0,0.2,0.4...
 static int /*writePos,*/ winPosInt,posFrac; //static float w, posFrac, winPos, winPosFrac; //printf("%.1f ",inputSignal);
 writePos = (bufPos>>FRACTIONAL_BITS) - (SincParts/2-1); //posFrac = (bufPos&FRACTIONAL_AND); //bufPos-writePos; //buffer write-pos int and frac parts (start: writePos=0, posFrac=0.0,0.2,0.4,...
 //writePos -= (SINCPARTS/2-1);
 if (writePos < 0) writePos += outBufLength; //writePos = bufPos-5 (window-middle), writePos=11,11,11,11,11,12,12,12,12,12,...
 winPosInt = SincPartReso - ( (bufPos&FRACTIONAL_AND) >> (FRACTIONAL_BITS-SincPartBits) ); // << (SINCPARTBITS-FRACTIONAL_BITS) );//-((bufPos&0xFF)>>1); //(1.0-posFrac) * SINCPARTRESO; //(float)(windowSize/SINCPARTS); //sinc-part position for writebuffer-position's fractional
 //winPosInt = (int)(winPos); if(DEBUG) printf(" %.2f-%d-%d: ", bufPos, writePos, winPosInt); //winPosFrac = winPos-winPosInt; //sinc-window position int and frac parts (winPosInt=128, winPosFrac=0.0)
 do {  //printf("%d,%d,%d,%d\n",writePos,winPosInt,windowSize,SincWindow[winPosInt]);
  //w = windowTable[winPosInt]; // + ( (windowTable[winPosInt+1] - windowTable[winPosInt]) * winPosFrac ); //interpolated inbetween sinc-value (w = difference between adjacent window-entries)
  outBuf[writePos] += (inputSignal * SincWindow[winPosInt]) / Magnitude; //>> 11; // / 2048; //*w; if(DEBUG) printf("%d,%d,%.2f ",writePos,winPosInt,w); //printf("%d:%.1f ",writePos,outBuf[writePos]); //inputSignal*w); //store processed inputsignal, convoluted (multiplied) by windowed-sinc value
  if (++writePos >= outBufLength) writePos = 0; //increase writePos with wraparound in buffer
  winPosInt += SincPartReso; //(windowSize/SINCPARTS); //step in windowed-sinc too, a whole sinc-part
 } while (winPosInt < windowSize); //stepping through the whole sinc-window (and write the 12 buf[] write-entries)
}


