signed int doSignal () {
 enum { PULSE_AMPLITUDE = 0x4000, PULSE_XOR=(PULSE_AMPLITUDE-1), PULSE_MID=(PULSE_AMPLITUDE/2) };
 static signed short FreqCnt=0, FrameCnt=0;
 static signed int Pulse=0x0000;
 if(FreqCnt>=0x3FF) { FreqCnt=(Freq+1)&0x3FF; Pulse^=PULSE_XOR; } //0x7FFF; }
 else ++FreqCnt;
 return Pulse-PULSE_MID; //0x4000;
}

