void soundCallback(void* userdata, unsigned char* buf, int len) {
 static unsigned short i;
 static signed short Output;
 for(i=0;i<len;i+=2) {
  Output = generateSound();
  buf[i]=Output&0xFF; buf[i+1]=Output>>8; //fputc(buf[i+1]+0x80,fp);
 }
}

