 //signed int FilterBuffer[];


 if (argc<2) { printf("\nGenerate resampling-window with given size and magnitude:\nresampling <filename> <partcount> <partlength> <magnitude>\n"); return 0; }

 int Periods=0, Samples=0, Magnitude=0;
 if (argc>=3) sscanf( argv[2], "%d", &Periods );
 if (argc>=4) sscanf( argv[3], "%d", &Samples );
 if (argc>=5) sscanf( argv[4], "%d", &Magnitude );

 generateResampleWindow( argv[1], Periods, Samples, Magnitude );
 printf("Downsample-ratio: %f\n\n",DOWNSAMPLE_RATIO);

 //fp=fopen("test.raw","wb");


#ifdef CRSID_RESAMPLING_TEST_SOUND
 for(j=0;j<WINSIZE;++j) x[j]=y[j]=0;

 if ( SDL_Init(SDL_INIT_AUDIO | SDL_INIT_VIDEO) < 0 ) {  //| SDL_INIT_TIMER
  fprintf(stderr, "Couldn't initialize SDL: %s\n",SDL_GetError()); return -1;
 }
 soundspec.freq=OUTPUT_SAMPLERATE;
 soundspec.channels=1;
 soundspec.format=AUDIO_S16;
 soundspec.samples=BUFFER_LENGTH; soundspec.userdata=NULL; soundspec.callback=soundCallback;
 if ( SDL_OpenAudio(&soundspec, NULL) < 0 ) {
  fprintf(stderr, "Couldn't open audio: %s\n", SDL_GetError()); return -1;
 }

 SDL_PauseAudio(0); printf("Press Enter to finish.\n"); getchar();

 SDL_CloseAudio();
#endif


